const items = $input.all();
const results = [];

for (const item of items) {
  try {
    let html = '';
    if (item.json.content && Array.isArray(item.json.content)) {
      html = item.json.content[0].text;
    } else if (item.json.text) {
      html = item.json.text;
    }
    const htmlStart = html.indexOf('<html');
    if (htmlStart !== -1) html = html.substring(htmlStart);
    results.push({ json: { resumeHtml: html } });
  } catch(e) {
    results.push({
      json: {
        resumeHtml: '<html><body>Error generating resume</body></html>',
        error: e.message
      }
    });
  }
}

return results;

const scrapedJobs = $input.all();

const staffingCompanies = [
  'infosys', 'wipro', 'tcs', 'tata consultancy', 'cognizant',
  'hcl', 'capgemini', 'hexaware', 'mastech', 'tekystems',
  'apex systems', 'insight global', 'robert half', 'randstad',
  'beaconfire', 'beacon fire', 'beacon hill', 'kforce', 'modis',
  'stefanini', 'luxoft', 'epam', 'globallogic', 'mphasis',
  'persistent systems', 'ltimindtree', 'mindtree', 'igate',
  'cyient', 'niit', 'syntel', 'revature', 'unison',
  'tech mahindra', 'birlasoft', 'zensar', 'sonata',
  'coforge', 'intelliswift', 'collabera'
];

const seen = new Set();
const newJobs = scrapedJobs.filter(item => {
  const link = item.json.link;
  const company = (item.json.companyName || '').toLowerCase();
  if (!link) return false;
  if (seen.has(link)) return false;
  if (staffingCompanies.some(bad => company.includes(bad))) return false;
  seen.add(link);
  return true;
});

console.log(`Total scraped: ${scrapedJobs.length}`);
console.log(`New unique jobs: ${newJobs.length}`);

return newJobs.map(item => ({ json: item.json }));
